proof_block:
// The function returns `()`, so `r1 == r2` is trivial.  The real obligation
// is on the components named in `det_*_equal`: `root_container`, the four
// perm-Map views (container_perms@, process_perms@, thread_perms@,
// endpoint_perms@) and `cpu_list@`.  Both post-states are pinned by the
// same ensures clauses against the shared `pre_self_`, so we triangulate
// every observable component through `pre_self_`.
assert(r1 == r2);

let ep_ptr = pre_self_.get_thread(thread_ptr)
    .endpoint_descriptors@[endpoint_index as int].unwrap();

// ── Domain equalities for the four perm maps ─────────────────────────────
// `container_dom() == container_perms@.dom()`, etc., are `#[verifier(inline)]`,
// so each post's `*_dom() == pre's *_dom()` clause already gives us domain
// equality between the two posts.
assert(post1_self_.container_perms@.dom() =~= post2_self_.container_perms@.dom());
assert(post1_self_.process_perms@.dom()   =~= post2_self_.process_perms@.dom());
assert(post1_self_.thread_perms@.dom()    =~= post2_self_.thread_perms@.dom());
assert(post1_self_.endpoint_perms@.dom()  =~= post2_self_.endpoint_perms@.dom());

// ── Procs: every proc in dom is preserved across both runs. ──────────────
// The ensures triggers are `#![trigger post1_self_.get_proc(p_ptr)]` and
// `#![trigger post2_self_.get_proc(p_ptr)]`; firing on both lets us
// triangulate through `pre_self_.get_proc(p_ptr)`.
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr)]
    #![trigger post2_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr)
    implies post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr)
         && post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr)
         && post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr) by {
}

// ── Containers: every container in dom is preserved across both runs. ────
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr)]
    #![trigger post2_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr)
    implies post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr)
         && post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr)
         && post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr) by {
}

// ── Threads: every thread other than `thread_ptr` is preserved. ──────────
// The ensures triggers are `#![trigger pre_self_.get_thread(t_ptr)]` for
// both posts, so firing on `pre_self_.get_thread(t_ptr)` discharges both.
assert forall|t_ptr: ThreadPtr|
    #![trigger pre_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr
    implies post1_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr)
         && post2_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr)
         && post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {
}

// ── The special thread `thread_ptr` is pinned identically in both runs. ──
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors
       =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors);
assert(post2_self_.get_thread(thread_ptr).endpoint_descriptors
       =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors);
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors
       =~= post2_self_.get_thread(thread_ptr).endpoint_descriptors);
assert(post1_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload);
assert(post2_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload);
assert(post1_self_.get_thread(thread_ptr).ipc_payload
       =~= post2_self_.get_thread(thread_ptr).ipc_payload);
assert(post1_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED);
assert(post2_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED);
assert(post1_self_.get_thread(thread_ptr).state
       == post2_self_.get_thread(thread_ptr).state);

// ── Endpoints other than `ep_ptr` are preserved across both runs. ────────
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr)]
    #![trigger post2_self_.get_endpoint(e_ptr)]
    post1_self_.endpoint_dom().contains(e_ptr) && e_ptr != ep_ptr
    implies post1_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr)
         && post2_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr)
         && post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr) by {
    assert(post2_self_.endpoint_dom().contains(e_ptr));
}

// ── The special endpoint `ep_ptr` is pinned identically in both runs. ────
assert(post1_self_.get_endpoint(ep_ptr).queue_state == queue_state);
assert(post2_self_.get_endpoint(ep_ptr).queue_state == queue_state);
assert(post1_self_.get_endpoint(ep_ptr).queue_state
       == post2_self_.get_endpoint(ep_ptr).queue_state);
assert(post1_self_.get_endpoint(ep_ptr).owning_threads
       == pre_self_.get_endpoint(ep_ptr).owning_threads);
assert(post2_self_.get_endpoint(ep_ptr).owning_threads
       == pre_self_.get_endpoint(ep_ptr).owning_threads);
assert(post1_self_.get_endpoint(ep_ptr).owning_threads
       =~= post2_self_.get_endpoint(ep_ptr).owning_threads);
assert(post1_self_.get_endpoint(ep_ptr).queue@
       == pre_self_.get_endpoint(ep_ptr).queue@.push(thread_ptr));
assert(post2_self_.get_endpoint(ep_ptr).queue@
       == pre_self_.get_endpoint(ep_ptr).queue@.push(thread_ptr));
assert(post1_self_.get_endpoint(ep_ptr).queue@
       =~= post2_self_.get_endpoint(ep_ptr).queue@);

// ── Pointwise key-by-key Map equality, then Map::ext_equal. ──────────────
// container_perms: every key is preserved (no container is modified).
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.container_perms@[c_ptr]]
    #![trigger post2_self_.container_perms@[c_ptr]]
    post1_self_.container_perms@.dom().contains(c_ptr)
    implies post1_self_.container_perms@[c_ptr]
            == post2_self_.container_perms@[c_ptr] by {
    assert(post2_self_.container_perms@.dom().contains(c_ptr));
    assert(pre_self_.container_perms@.dom().contains(c_ptr));
}
assert(post1_self_.container_perms@ =~= post2_self_.container_perms@);

// process_perms: every key is preserved (no proc is modified).
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.process_perms@[p_ptr]]
    #![trigger post2_self_.process_perms@[p_ptr]]
    post1_self_.process_perms@.dom().contains(p_ptr)
    implies post1_self_.process_perms@[p_ptr]
            == post2_self_.process_perms@[p_ptr] by {
    assert(post2_self_.process_perms@.dom().contains(p_ptr));
    assert(pre_self_.process_perms@.dom().contains(p_ptr));
}
assert(post1_self_.process_perms@ =~= post2_self_.process_perms@);

// thread_perms: every key in dom; for t != thread_ptr preserved from pre,
// for t == thread_ptr both posts pin the same (endpoint_descriptors,
// ipc_payload, state).
assert forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.thread_perms@[t_ptr]]
    #![trigger post2_self_.thread_perms@[t_ptr]]
    post1_self_.thread_perms@.dom().contains(t_ptr)
    implies post1_self_.thread_perms@[t_ptr]
            == post2_self_.thread_perms@[t_ptr] by {
    assert(post2_self_.thread_perms@.dom().contains(t_ptr));
    assert(pre_self_.thread_perms@.dom().contains(t_ptr));
}
assert(post1_self_.thread_perms@ =~= post2_self_.thread_perms@);

// endpoint_perms: every key in dom; for e != ep_ptr preserved from pre,
// for e == ep_ptr both posts pin the same (queue_state, owning_threads,
// queue@).
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.endpoint_perms@[e_ptr]]
    #![trigger post2_self_.endpoint_perms@[e_ptr]]
    post1_self_.endpoint_perms@.dom().contains(e_ptr)
    implies post1_self_.endpoint_perms@[e_ptr]
            == post2_self_.endpoint_perms@[e_ptr] by {
    assert(post2_self_.endpoint_perms@.dom().contains(e_ptr));
    assert(pre_self_.endpoint_perms@.dom().contains(e_ptr));
}
assert(post1_self_.endpoint_perms@ =~= post2_self_.endpoint_perms@);

// ── Page closure and the other dom equalities propagate. ─────────────────
assert(post1_self_.page_closure() =~= post2_self_.page_closure());
assert(post1_self_.endpoint_dom() == post2_self_.endpoint_dom());
assert(post1_self_.container_dom() == post2_self_.container_dom());
assert(post1_self_.thread_dom() == post2_self_.thread_dom());
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
